/* Relevance prefilter: simple keyword scoring, then pick top N (5) */
const KEYWORDS = ['crispr','gene therapy','synthetic biology','delivery','deliver','vector','therapeutic','therapeutics','cell therapy','gene editing','gene-editing'];
const scored = items.map(i=>{
  const title = (i.json.title||'').toString().toLowerCase();
  const abstract = (i.json.abstract||'').toString().toLowerCase();
  let score = 0;
  for (const kw of KEYWORDS) {
    if (title.includes(kw)) score += 3;
    if (abstract.includes(kw)) score += 2;
  }
  // boost shorter titles + non-empty abstract
  if ((abstract||'').length > 200) score += 1;
  score += Math.min(2, (title.length>0)?1:0);
  return {score, json: i.json};
});
scored.sort((a,b)=>b.score - a.score);
const limit = 5;
return scored.slice(0, limit).map(s=>({json: {...s.json, prefilter_score: s.score}}));

/* Enhanced Robust JSON extraction with error logging */
const response = $input.first().json;
let content = '';
if (response.choices && response.choices[0] && response.choices[0].message && response.choices[0].message.content) {
  content = response.choices[0].message.content;
} else if (response.error) {
  return [{ json: { error: 'OpenAI API Error', details: response.error } }];
} else {
  content = '{}';
}
try {
  const parsed = JSON.parse(content);
  return [{ json: parsed }];
} catch (e) {
  const m = content.match(/\{[\s\S]*\}/);
  if (m) {
    try { return [{ json: JSON.parse(m[0]) }]; } catch(err) { return [{ json: { error: 'JSON parse failed', rawContent: content, parseError: err.message } }]; }
  }
  return [{ json: { error: 'JSON parse failed', rawContent: content, parseError: e.message } }];
}

/* Aggregate items back into a single email body */
const lines = [];
for (const it of items) {
  const j = it.json;
  lines.push(`Title: ${j.title || 'Untitled'}
Authors: ${j.authors || 'Unknown'}
Relevance score: ${j.relevance_score || 0}
URL: ${j.url || 'No URL'}
Summary: ${j.summary || (j.abstract || '').slice(0,300)}
---`);
}
const body = lines.join('

');
return [{ json: { emailBody: `New papers from BioIntel run (top ${items.length}):

${body}` } }];

