/* Normalize merged items to a unified shape */
const out = [];
for (const item of items) {
  // PubMed esummary results come as esummaryresult -> result -> uid keyed objects
  if (item.json.result) {
    for (const key of Object.keys(item.json.result)) {
      if (key === 'uids') continue;
      const r = item.json.result[key];
      out.push({
        json: {
          title: r.title || r.Title || '',
          authors: (r.authors && r.authors.map(a => a.name).join(', ')) || r.authors || '',
          abstract: r.elocationid || r.title || '',
          source: 'PubMed',
          url: r.uid ? `https://pubmed.ncbi.nlm.nih.gov/${r.uid}/` : ''
        }
      });
    }
    continue;
  }

  // Generic handlers
  if (item.json && item.json.rss && item.json.rss.channel && item.json.rss.channel.item) {
    const itemsArr = item.json.rss.channel.item;
    const feed = Array.isArray(itemsArr) ? itemsArr : [itemsArr];
    for (const r of feed) {
      out.push({json: {
        title: r.title || '',
        authors: r['dc:creator'] || '',
        abstract: r.description || '',
        source: 'ArXiv',
        url: r.link || ''
      }});
    }
    continue;
  }

  if (item.json.title) {
    out.push({json: {
      title: item.json.title,
      authors: item.json.authors || '',
      abstract: item.json.abstract || item.json.summary || '',
      source: item.json.source || 'Unknown',
      url: item.json.url || ''
    }});
  }
}
return out;

/* Remove duplicates by title+authors+url (case-insensitive) */
const map = new Map();
for (const it of items) {
  const t = (it.json.title || '').toString().trim().toLowerCase();
  const a = (it.json.authors || '').toString().trim().toLowerCase();
  const u = (it.json.url || '').toString().trim().toLowerCase();
  const key = `${t}||${a}||${u}`;
  if (!map.has(key)) map.set(key, it);
}
return Array.from(map.values());

/* Parse response object into fields and ensure authors string */
const out = [];
for (const it of items) {
  let parsed = it.json || {};
  // Normalize minimal fields
  parsed.title = parsed.title || $input.all()[0].json.title || '';
  parsed.authors = parsed.authors ? (Array.isArray(parsed.authors) ? parsed.authors.join(', ') : parsed.authors.toString()) : 'Unknown';
  parsed.domain = parsed.domain || '';
  parsed.summary = parsed.summary || '';
  parsed.biological_mechanism = parsed.biological_mechanism || '';
  parsed.applications = parsed.applications || '';
  parsed.TRL_level = parsed.TRL_level || '';
  parsed.commercial_potential = parsed.commercial_potential || '';
  parsed.industry_relevance = parsed.industry_relevance || '';
  parsed.relevance_score = Number(parsed.relevance_score) || Number(parsed.prefilter_score) || 0;
  out.push({ json: parsed });
}
return out;
